cd /tmp/sv-d87aacd3fb6b4480aa3c525d08d377bf/ResearchAgent
# Use a quick C# program to enumerate the types
cat > /tmp/TypeExplorer.csx << 'SCRIPT'
var asm = System.Reflection.Assembly.LoadFrom(args[0]);
foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine(t.FullName);
    foreach (var m in t.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.DeclaredOnly))
        Console.WriteLine($"  .{m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
    foreach (var p in t.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.DeclaredOnly))
        Console.WriteLine($"  [{p.PropertyType.Name}] {p.Name}");
    foreach (var c in t.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
SCRIPT

# Write a quick program to do the exploration
mkdir -p /tmp/typecheck && cd /tmp/typecheck
cat > Program.cs << 'EOF'
using System.Reflection;

var dllPath = args[0];
var asm = Assembly.LoadFrom(dllPath);

foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine($"\n=== {t.FullName} ===");
    foreach (var c in t.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop [{p.PropertyType.Name}] {p.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
EOF

