using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Build the IChatClient through the MEAI abstraction
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ---------------------------------------------------------------------------
// Create tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ---------------------------------------------------------------------------
// Create the research agent  (Microsoft Agent Framework)
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When the user gives you a topic:
        1. Use the web_search tool to search for information. Try several
           queries to cover different angles of the topic.
        2. After each search, call add_note with key findings worth remembering.
        3. When you have gathered enough material, call get_notes to review
           everything you collected.
        4. Produce a well-structured summary with sections, key facts, and
           source URLs where available.
        Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools",
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍  Research Agent  🔍        ║");
Console.WriteLine("╠══════════════════════════════════════╣");
