/// <summary>Web search tool backed by the DuckDuckGo Instant Answer API.</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns a summary and related topics.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"**Summary**: {abstractText}\nSource: {abstractUrl}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var topic in related.EnumerateArray().Take(8))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"• {text}\n  URL: {firstUrl}");
                }
            }

            // Answer (for factual/calculation queries)
            var answer = root.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
                results.Add($"**Direct Answer**: {answer}");

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No results found for '{query}'. Try rephrasing or using different keywords.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

